import os
import json
import argparse
import numpy as np
import heapq
from cogniplan_env import ExplorationEnv

def get_action(obs):
    nodes = obs["nodes"]
    neighbors = obs["neighbors"]
    if not neighbors: return None

    graph = {}
    utility_map = {}
    visited_map = {}
    for node in nodes:
        coords = tuple(np.round(node["coords"], 2))
        graph[coords] = [tuple(np.round(n, 2)) for n in node["neighbors"]]
        utility_map[coords] = node["utility"]
        visited_map[coords] = node.get("visited", False)

    robot_pos = tuple(np.round(obs["robot_pos"], 2))

    queue = []
    visited = {robot_pos: 0.0}
    node_info = {}

    for n in neighbors:
        n_tuple = tuple(np.round(n, 2))
        dist = np.hypot(n_tuple[0] - robot_pos[0], n_tuple[1] - robot_pos[1])
        heapq.heappush(queue, (dist, n_tuple, n_tuple))
        visited[n_tuple] = dist
        node_info[n_tuple] = (n_tuple, dist)

    while queue:
        dist, curr, first_step = heapq.heappop(queue)
        if dist > visited.get(curr, float('inf')):
            continue

        for nxt in graph.get(curr, []):
            edge_dist = np.hypot(nxt[0] - curr[0], nxt[1] - curr[1])
            new_dist = dist + edge_dist
            if nxt not in visited or new_dist < visited[nxt] - 1e-3:
                visited[nxt] = new_dist
                heapq.heappush(queue, (new_dist, nxt, first_step))
                node_info[nxt] = (first_step, new_dist)

    best_score = -float('inf')
    best_action = None

    best_unvisited_dist = float('inf')
    best_unvisited_action = None

    for node_coords, (first_step, dist) in node_info.items():
        u = utility_map.get(node_coords, 0)
        is_visited = visited_map.get(node_coords, False)

        if not is_visited:
            if dist < best_unvisited_dist:
                best_unvisited_dist = dist
                best_unvisited_action = first_step

        if u > 0:
            score = u * np.exp(-0.1 * dist)
            if score > best_score:
                best_score = score
                best_action = first_step

    chosen_action = best_action if best_action is not None else best_unvisited_action
    if chosen_action is None:
        chosen_action = tuple(np.round(neighbors[0], 2))

    for n in neighbors:
        if tuple(np.round(n, 2)) == chosen_action:
            return n
    return neighbors[0]

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, required=True)
    parser.add_argument("--checkpoint", type=str, required=True)
    parser.add_argument("--output", type=str, required=True)
    args = parser.parse_args()

    eval_config_path = os.path.join(args.data_path, "eval_config.json")
    with open(eval_config_path, "r") as f:
        eval_config = json.load(f)

    maps_eval_dir = os.path.join(args.data_path, "maps_eval")

    map_files = []
    if "maps" in eval_config:
        map_files = eval_config["maps"]
    else:
        for root, dirs, files in os.walk(maps_eval_dir):
            for file in files:
                if file.endswith(".png"):
                    rel_path = os.path.relpath(os.path.join(root, file), maps_eval_dir)
                    map_files.append(rel_path)

    results = []
    per_type = {}

    for map_file in map_files:
        map_path = os.path.join(maps_eval_dir, map_file)
        env_type = os.path.basename(os.path.dirname(map_path))
        if env_type not in per_type:
            per_type[env_type] = {"explored_rate": [], "travel_distance": [], "success": []}

        env = ExplorationEnv(map_path=map_path)
        obs = env.reset()

        for step in range(128):
            target = get_action(obs)
            if target is None:
                break

            obs, info = env.step(target)
            if info["done"]:
                break

        metrics = env.get_metrics()
        success = 1 if metrics["success"] else 0
        results.append({
            "map_path": map_file,
            "env_type": env_type,
            "success": success,
            "travel_distance": metrics["travel_distance"],
            "explored_rate": metrics["explored_rate"]
        })

        per_type[env_type]["explored_rate"].append(metrics["explored_rate"])
        if success:
            per_type[env_type]["travel_distance"].append(metrics["travel_distance"])
        per_type[env_type]["success"].append(success)

    total_episodes = len(results)
    success_rate = np.mean([r["success"] for r in results])
    explored_rate = np.mean([r["explored_rate"] for r in results])

    successful_distances = [r["travel_distance"] for r in results if r["success"]]
    travel_distance = np.mean(successful_distances) if successful_distances else 0.0

    for env_type, data in per_type.items():
        data["explored_rate"] = np.mean(data["explored_rate"])
        data["success_rate"] = np.mean(data["success"])
        data["travel_distance"] = np.mean(data["travel_distance"]) if data["travel_distance"] else 0.0
        del data["success"]

    output_data = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": results,
        "per_type": per_type,
        "total_episodes": total_episodes
    }

    with open(args.output, "w") as f:
        json.dump(output_data, f, indent=2)

if __name__ == "__main__":
    main()
